    float detail = tanhf((L_norm - blur_norm) * 3.0f) / 3.0f;
    float L_new = fminf(fmaxf(L_norm + detail * clarity_amount, 0.0f), 1.0f);

    // Reconstruct RGB: only L changed, A and B unchanged
